mapper.select:

select case when
ISNULL(
(select pe.id from  pm_employee pe where right(cast('000000'+rtrim(pe.work_card) as varchar),6) =

right(cast('000000'+rtrim(#{workCard,jdbcType=VARCHAR}) as varchar),6) and pe.enabled_flag = 1 and pe.leave_flag = 0
and pe.name = #{name,jdbcType=VARCHAR}
), '-1') = -1 then 0 else 1 end


select case when exists (
    select 1 from ac_overtime_leave_interface where data_status = 'T' and date_str =  #{incomePeriod, jdbcType = VARCHAR}
) then 1 else 0 end
